        public AsyncResultController(global::IAsyncResultService iAsyncResultService)
        {
            this.iAsyncResultService = iAsyncResultService;
        }

        [Route("ProcessFileAsync")]
        [HttpPost]
        public async global::System.Threading.Tasks.Task<string> ProcessFileAsync([FromForm] __ProcessFileAsync_FormArg arg)
        {
            using var __sb_file = YS.Knife.StreamBody.FromStream(arg.file.OpenReadStream(), arg.file.ContentType, arg.file.FileName, arg.file.Length);
